import { G, T, A, O, P } from './domains.js';

export const part3 = [
  {id:253,domain:P,question:"What is a security operations center (SOC)?",options:["A physical room where servers are kept","A centralized team and facility monitoring and responding to security events 24/7","A cloud-hosted SaaS vulnerability management application that aggregates scanner results and tracks remediation workflow tickets across the enterprise","An internal team of compliance auditors that reviews organizational adherence to regulatory frameworks and security control standards"],answer:1,explanation:"A SOC combines people, processes, and technology to continuously monitor, detect, analyze, and respond to security threats.",optionExplanations:["A data center is the physical server room; a SOC focuses on security monitoring and response.","A SOC is the hub of continuous security monitoring, threat detection, and incident response operations.","A vulnerability management platform tracks patching and remediation; a SOC is a centralized team and facility staffed around the clock to monitor and respond to security events.","Compliance audit teams assess regulatory adherence periodically; a SOC is an operational security function staffed 24/7 to detect, analyze, and respond to active security threats."]},
  {id:254,domain:G,question:"Which of the following describes the concept of tokenization in data security?",options:["Applying reversible AES-256 encryption to sensitive data fields so they can be decrypted using the corresponding encryption key when needed","Replacing sensitive data with a non-sensitive placeholder (token) that maps back to the original in a secure vault","Applying a one-way SHA-256 cryptographic hash function to sensitive data to produce a fixed-length digest for safe storage","Distributing fragments of sensitive records across multiple geographically separated servers to reduce the exposure from any single data breach"],answer:1,explanation:"Tokenization replaces sensitive data (like credit card numbers) with non-sensitive tokens; the mapping is in a secure token vault.",optionExplanations:["Encrypting data produces a ciphertext decryptable with the key; tokenization replaces data with a random token that has no mathematical relationship to the original, stored separately in a vault.","Tokenization substitutes sensitive values with tokens that have no exploitable mathematical relationship to the original.","Hashing is a one-way transformation producing a fixed digest; tokenization replaces data with a random placeholder token that maps back to the original only in a secure vault.","Distributing data across servers describes data sharding or secret splitting; tokenization replaces sensitive values with random tokens that can only be reversed via a separate secure vault."]},
  {id:255,domain:G,question:"What is the purpose of FIDO2 / WebAuthn?",options:["Provide fully encrypted email communication channels between two corresponding parties","Enable passwordless authentication using hardware keys or device biometrics","Manage the full issuance and revocation lifecycle of digital certificates","Encrypt web browsing sessions end-to-end between the client and server"],answer:1,explanation:"FIDO2/WebAuthn enables strong authentication via hardware security keys (YubiKey) or device biometrics, eliminating passwords.",optionExplanations:["Email encryption is handled by S/MIME and PGP, which is unrelated to FIDO2's web authentication purpose.","FIDO2 provides strong, phishing-resistant authentication using public-key cryptography with hardware keys or biometrics.","Certificate lifecycle management is handled by PKI systems, while FIDO2 is instead an authentication protocol.","TLS/HTTPS is what encrypts web sessions; FIDO2 instead handles the separate step of authenticating the user."]},
  {id:256,domain:T,question:"What is a RAT (Remote Access Trojan)?",options:["A specific software vulnerability discovered within legitimate remote desktop protocol software","Malware giving attackers hidden remote control of a victim's system","A legitimate, IT-sanctioned remote administration tool used for authorized support tasks","A specific technique used to bypass firewall rules and evade network filtering"],answer:1,explanation:"RATs silently install themselves and give attackers full remote control including file access, webcam, microphone, and keylogging.",optionExplanations:["RDP vulnerabilities are CVEs found in Microsoft's protocol, which is a different concept from a RAT malware category.","A RAT is a Trojan that creates a hidden backdoor giving attackers persistent, covert remote control of the system.","Legitimate remote admin tools, like RDP or SSH, are authorized and visible, unlike a RAT which is covertly installed malware.","Firewall bypass techniques use tunneling or port manipulation; a RAT instead exploits the remote access it covertly establishes, not firewalls directly."]},
  {id:257,domain:T,question:"What is a pass-the-hash attack?",options:["Sending the same request to a server multiple times","Using a captured NTLM password hash to authenticate without knowing the plaintext password","Distributing the same bcrypt-hashed password value to multiple user accounts so they share identical credential representations in the directory","Using precomputed rainbow table lookups to reverse-engineer MD5 password hashes stolen from a compromised authentication database"],answer:1,explanation:"Pass-the-hash exploits Windows NTLM: an attacker captures the hash and uses it directly to authenticate, bypassing the need for plaintext.",optionExplanations:["Replaying requests is a replay attack; pass-the-hash specifically reuses authentication hashes.","Pass-the-hash uses a captured NTLM hash as the authentication credential without needing to crack it.","Sharing identical password hashes among accounts is a credential provisioning issue; pass-the-hash uses a stolen hash from one account to authenticate as that specific user elsewhere.","Rainbow table attacks crack weak hashes to recover plaintext passwords; pass-the-hash uses the hash itself directly for NTLM authentication without needing to crack it first."]},
  {id:258,domain:T,question:"What is privilege escalation?",options:["Enrolling a staff member in advanced technical certification courses or professional development programs to improve their job performance","Gaining higher-level access rights than originally granted, either through exploitation or misconfiguration","Elevating the importance of a security incident","Issuing time-limited administrative credentials to a technician to allow them to perform scheduled maintenance on specific systems"],answer:1,explanation:"Privilege escalation exploits vulnerabilities or misconfigurations to obtain higher privileges, such as gaining admin from a standard user account.",optionExplanations:["Providing training is a human resources activity unrelated to security exploitation; privilege escalation is the technical act of gaining higher system access through exploitation or misconfiguration.","Privilege escalation gains more access than originally assigned, often exploiting kernel vulnerabilities or misconfigured permissions.","Incident severity escalation is an IR process step; privilege escalation is an attack technique.","Temporary admin access for maintenance is an authorized IAM practice; privilege escalation involves gaining elevated access through exploitation or misconfiguration, not legitimate provisioning."]},
  {id:259,domain:T,question:"Which of the following is a characteristic of a polymorphic virus?",options:["It is restricted to infecting only one specific type of executable file","It changes its code signature with each infection to evade detection","It encrypts all of a victim's personal files and demands a ransom payment","It self-replicates continuously across systems without requiring any host file at all"],answer:1,explanation:"Polymorphic malware mutates its code each replication cycle, making signature-based detection very difficult.",optionExplanations:["File-type specificity is a property some viruses share, but it is not what defines polymorphic behavior.","Polymorphic viruses alter their own code (encryption, code mutation) each time they replicate, evading signature detection.","Encrypting files for ransom describes ransomware, a completely different malware category from polymorphism.","Self-replication without a host file defines a worm, whereas polymorphism describes code mutation to evade detection."]},
  {id:260,domain:T,question:"What is a Trojan dropper?",options:["A Trojan that deletes files when triggered","Malware whose primary function is to install other malware on the system","File-encrypting malware that locks all accessible data and displays a ransom demand requiring cryptocurrency payment to restore access","A Trojan that steals files and sends them to a C2 server"],answer:1,explanation:"A dropper's purpose is to deliver and install additional malicious payloads (ransomware, RATs, backdoors) on the victim system.",optionExplanations:["File deletion is the function of a wiper or destructive payload; droppers deliver other malware.","A dropper is a stage-one payload whose sole job is to download and install the actual malware payload.","Ransomware encrypts files and demands payment to restore access; a Trojan dropper is specifically designed to secretly install additional malware payloads on the compromised system.","Data exfiltrating Trojans are stealers; droppers install other malware rather than stealing data themselves."]},
  {id:261,domain:A,question:"Which of the following is a security advantage of using private cloud over public cloud?",options:["Private cloud is always cheaper","Greater control over the infrastructure and data isolation","Unlimited scalability without security concerns","No need for encryption"],answer:1,explanation:"Private cloud gives organizations full control over their hardware, network, and data placement — important for sensitive data.",optionExplanations:["Private cloud typically costs more due to dedicated infrastructure; public cloud benefits from shared cost.","Private cloud provides dedicated infrastructure, greater customization, and better isolation for sensitive workloads.","Public cloud offers greater scalability; private cloud trades some scalability for control.","Encryption is required in both private and public cloud environments."]},
  {id:262,domain:A,question:"What is the purpose of a demilitarized zone (DMZ) in a network?",options:["Store the organization's most sensitive internal data in a highly protected repository","Host public-facing services between two firewalls while protecting the internal network","Completely eliminate the need for any firewalls elsewhere on the network","Provide wireless network access to visitors and staff throughout the facility"],answer:1,explanation:"The DMZ isolates publicly accessible servers (web, email) from the internal network using a double-firewall architecture.",optionExplanations:["The most sensitive data belongs in the most protected internal zone, which is the opposite of the exposed DMZ.","A DMZ places public servers between external and internal firewalls, providing buffer separation from the trusted network.","DMZs work alongside firewalls and actually require at least two firewall layers to function; they do not replace firewalls.","Wireless access points are separate infrastructure entirely, while a DMZ is a network segmentation architecture."]},
  {id:263,domain:A,question:"What is the purpose of a proxy auto-config (PAC) file?",options:["Dynamically push and apply updated firewall access control list rules to network edge devices based on current threat intelligence feeds","Allow browsers to automatically determine whether to use a proxy server for a given URL","Automatically distribute VPN gateway addresses and authentication settings to remote employee devices during VPN client software installation","Push DNS resolver addresses and search domain suffix lists to endpoints via DHCP options during IP address lease assignment"],answer:1,explanation:"A PAC file is a JavaScript function browsers call to decide whether to use a proxy and which one for each URL.",optionExplanations:["Dynamic firewall rule updates are threat intelligence integration; a PAC file helps browsers determine when to route requests through a proxy based on URL-matching functions.","A PAC file defines logic for browsers to select proxy servers based on URL patterns, domains, and IP ranges.","VPN client provisioning configures remote access connectivity; a PAC file guides the browser's proxy selection logic for specific URLs, not VPN or network-level routing.","DHCP options distribute DNS and network settings; a PAC file is a JavaScript function that browsers execute to determine whether a given URL should be routed via proxy."]},
  {id:264,domain:A,question:"Which cloud deployment model combines private and public cloud environments?",options:["Community cloud","Multi-cloud","Hybrid cloud","Public cloud"],answer:2,explanation:"Hybrid cloud links private and public cloud environments, enabling workloads to move between them based on needs.",optionExplanations:["Community cloud is shared among organizations with similar requirements (e.g., government agencies).","Multi-cloud uses multiple public cloud providers without necessarily connecting to private infrastructure.","Hybrid cloud integrates private cloud (or on-premises) with public cloud services through unified management.","Public cloud is entirely operated by a third-party provider with no private component."]},
  {id:265,domain:A,question:"What is the risk of using default credentials on network devices?",options:["Default credentials are actually more secure than any custom credentials an administrator could choose","Attackers can easily access devices because defaults are publicly known","Default credentials are permanently hardcoded into the device and can never be changed","Default credentials are protected using a stronger, proprietary vendor encryption scheme"],answer:1,explanation:"Default credentials (admin/admin, admin/password) are documented in vendor manuals and widely known to attackers.",optionExplanations:["Default credentials are weak because they are identical across every device of the same model and are publicly documented.","Default credentials are in vendor documentation and security databases, making them trivial for attackers to exploit.","Default credentials can and must be changed; doing so is a critical first step in hardening any device.","Default credentials have no inherent relationship to encryption strength; they are simply authentication values, often weak ones."]},
  {id:266,domain:O,question:"What is the purpose of a forensic write blocker?",options:["Restrict forensic analysts from duplicating, copying, or exporting any files or partition images found on evidence storage media","Allow reading storage media without any possibility of modifying it during forensic analysis","Apply parallel processing algorithms to compress forensic disk images and reduce the total time required to acquire large drives","Apply AES-256 encryption to completed disk images to protect their confidentiality and integrity during storage and chain-of-custody transfers"],answer:1,explanation:"A write blocker ensures forensic examination does not inadvertently alter evidence by blocking any write commands to the media.",optionExplanations:["Preventing analysts from copying data would hinder forensic investigation; a write blocker allows unrestricted reading while specifically preventing any writes that would alter evidence.","Write blockers are hardware or software devices that intercept write commands, ensuring evidence remains unmodified during analysis.","Compression speeds up storage of images but is separate from write blocking; a write blocker's purpose is preventing modifications to source media, not accelerating image acquisition.","Encrypting acquired images protects them in transit; a write blocker is a hardware or software device that prevents any modification to the source media during the imaging process."]},
  {id:267,domain:O,question:"What is the purpose of a master boot record (MBR) in forensics?",options:["A dedicated hardware security chip embedded on the motherboard that generates and stores cryptographic keys and measures platform integrity","The first sector of a storage device containing bootloader code and partition table, sometimes targeted by bootkits","A system database file that stores hashed user account passwords, group memberships, and local security policy settings for authentication","A PXE-enabled network boot server that distributes operating system images to diskless workstations across the LAN on demand"],answer:1,explanation:"The MBR is forensically significant because malware (bootkits) can hide there before the OS loads, evading most security tools.",optionExplanations:["A hardware chip storing keys and measuring integrity describes a TPM, not the MBR; the MBR is the first disk sector holding boot code and partition table, sometimes targeted by bootkits.","The MBR is the first physical sector of a drive, containing boot instructions and partition information; bootkits infect it for persistence.","A password/policy database file describes the SAM or /etc/shadow, not the MBR; the MBR is the first sector of a storage device containing boot code and partition information.","A PXE boot server provides network-based OS deployment; the MBR is the first physical sector of a local storage device containing bootloader code and the partition table."]},
  {id:268,domain:O,question:"What is the MITRE ATT&CK framework?",options:["A regulatory compliance standard specifying mandatory cybersecurity controls for banks and financial services firms under federal oversight","A knowledge base of adversary tactics, techniques, and procedures (TTPs) based on real-world observations","A software development methodology that integrates security requirements and code review checkpoints throughout each phase of the development lifecycle","A standardized document template providing step-by-step guidance for security teams responding to common incident categories"],answer:1,explanation:"MITRE ATT&CK catalogs attacker TTPs organized by attack lifecycle stages, used for threat hunting, detection, and red team planning.",optionExplanations:["Regulatory standards for financial institutions include PCI DSS or GLBA; MITRE ATT&CK is a non-regulatory knowledge base of real-world adversary tactics, techniques, and procedures.","MITRE ATT&CK documents real-world adversary behaviors organized into tactics (goals) and techniques (methods).","Integrating security into development describes DevSecOps or SDLC security practices; MITRE ATT&CK catalogs attacker behaviors observed in real incidents, not development methodologies.","Step-by-step incident guidance describes a runbook or playbook; MITRE ATT&CK is a threat intelligence knowledge base cataloging attacker TTPs based on real-world observation."]},
  {id:269,domain:O,question:"What is the Cyber Kill Chain?",options:["A vendor risk management methodology for systematically assessing and securing third-party supplier and software supply chain relationships","Lockheed Martin's model describing the stages of a cyberattack from reconnaissance to exfiltration","A regulatory compliance audit checklist that helps organizations validate adherence to mandatory security controls and reporting requirements","A network architecture design model that divides infrastructure into isolated security zones separated by firewalls and access controls"],answer:1,explanation:"The Cyber Kill Chain models attacks in 7 stages: Reconnaissance, Weaponization, Delivery, Exploitation, Installation, C2, Actions on Objectives.",optionExplanations:["Supply chain risk management addresses third-party vendor risk; the Cyber Kill Chain is Lockheed Martin's model describing the sequential stages of a cyberattack from start to exfiltration.","The Cyber Kill Chain (Lockheed Martin) describes the sequential stages attackers follow, enabling defenders to break the chain.","A compliance checklist validates regulatory control adherence; the Cyber Kill Chain is a threat modeling framework describing attack progression stages, not a compliance validation tool.","Network segmentation models define zone-based architecture; the Cyber Kill Chain is a sequential attack lifecycle model describing how adversaries progress from reconnaissance to their objectives."]},
  {id:270,domain:O,question:"What is the difference between MTTD and MTTR?",options:["MTTD and MTTR are identical and interchangeable performance metrics both measuring the speed of incident detection and remediation","MTTD is the mean time to detect a threat; MTTR is the mean time to repair/recover","MTTD quantifies how quickly a failed system is fully restored to operational status; MTTR measures how rapidly security threats are first detected","Both MTTD and MTTR calculate the average interval of time elapsed between consecutive security incidents affecting the same organizational systems"],answer:1,explanation:"MTTD measures how long it takes to detect a threat; MTTR measures how long to recover. Both are key SOC performance metrics.",optionExplanations:["They are not identical; MTTD (Mean Time To Detect) measures how long before a threat is identified, while MTTR (Mean Time To Repair) measures how long restoration takes.","MTTD (Mean Time to Detect) and MTTR (Mean Time to Repair/Respond) are distinct metrics measuring detection and recovery speed.","This reverses the definitions; MTTD measures time to detect a threat, while MTTR measures the time to repair or recover from an incident after it has been detected.","Neither metric measures time between incidents; MTTD measures detection latency for individual threats, and MTTR measures the recovery duration for individual incidents."]},
  {id:271,domain:P,question:"What is the purpose of a gap analysis in security?",options:["Run automated endpoint detection tools to identify and classify malicious software present on organizational computing assets","Compare current security posture against a target standard to identify what needs improvement","Use automated scanning tools to probe all network-connected hosts and enumerate services listening on accessible TCP and UDP ports","Deliver targeted security awareness training sessions addressing specific knowledge gaps found during an employee phishing simulation assessment"],answer:1,explanation:"A gap analysis identifies the difference between the current state of security and a desired target state (framework, standard, or regulation).",optionExplanations:["Scanning for malware is a threat detection activity; a gap analysis compares current security posture against a target standard to identify areas requiring investment or improvement.","A gap analysis systematically compares current controls against required controls, identifying what is missing or insufficient.","Port scanning discovers exposed network services; a gap analysis compares the organization's existing security capabilities against a framework or target maturity level to find shortfalls.","Training staff addresses identified weaknesses; a gap analysis is the structured process of comparing current state to a target standard, not the remediation activity that follows it."]},
  {id:272,domain:P,question:"Which framework is specifically designed for securing industrial control systems (ICS)?",options:["NIST CSF","NERC CIP","PCI DSS","ISO 27001"],answer:1,explanation:"NERC CIP (North American Electric Reliability Corporation Critical Infrastructure Protection) standards apply to bulk electric system security.",optionExplanations:["NIST CSF is a general cybersecurity framework applicable to all sectors.","NERC CIP is specifically designed for protecting the bulk power system and electric utilities from cybersecurity threats.","PCI DSS applies to payment card data environments, not industrial control systems.","ISO 27001 is a general information security management standard, not specific to ICS."]},
  {id:273,domain:P,question:"What is a penetration testing scope document?",options:["A formal findings report produced after testing that catalogs all security vulnerabilities discovered, rated by exploitability and severity","A written agreement defining the boundaries, targets, and rules of engagement for a pen test","A remediation roadmap document prioritizing recommended security improvements and fixes identified during the completed assessment engagement","A technical setup guide explaining how to install, configure, and calibrate scanning and exploitation tools before beginning a security assessment"],answer:1,explanation:"The scope document (rules of engagement) defines what can be tested, which methods are permitted, and the testing timeline.",optionExplanations:["A findings report documents discovered issues; the scope document is created before testing begins and defines the boundaries, authorized targets, and rules of engagement for the engagement.","A scope document defines boundaries, IP ranges, allowed techniques, contact information, and the test window.","A remediation roadmap addresses findings after the test; the scope document is a pre-engagement agreement defining what systems may be tested and what techniques are authorized.","A tool configuration guide is an operational reference; the scope document is a legal agreement defining the authorized boundaries, objectives, and rules of engagement for the test."]},
  {id:274,domain:P,question:"What is the purpose of a vulnerability disclosure policy?",options:["Require all external parties to sign legal non-disclosure agreements before any security vulnerability information may be shared with the organization","Define how the organization wants to receive, process, and respond to security vulnerability reports from researchers","Configure automated patch management systems to deploy remediation for every discovered vulnerability within 24 hours of initial detection","Establish a financial incentive program that rewards security researchers with monetary bounties for every confirmed vulnerability they report"],answer:1,explanation:"A VDP sets expectations for responsible disclosure, encouraging researchers to report vulnerabilities safely without legal fear.",optionExplanations:["NDAs are legal instruments, not a disclosure policy; a vulnerability disclosure policy defines the process for receiving, triaging, and responding to vulnerability reports from external researchers.","A VDP establishes a clear process for researchers to report vulnerabilities, promising legal protection and response timelines.","Automated patching timelines are a patch management policy; a vulnerability disclosure policy defines how researchers should submit findings and how the organization will communicate and respond.","A bug bounty program is one specific mechanism for receiving reports; a vulnerability disclosure policy is a broader framework defining how all vulnerability reports are received and processed."]},
  {id:275,domain:P,question:"What is a memorandum of understanding (MOU) in security context?",options:["A fully binding legal contract enforceable in court between two separate organizations","A non-binding agreement establishing shared understanding of security responsibilities between parties","A detailed technical configuration document specifying exact system and network settings","An itemized vendor invoice listing charges for delivered security consulting services"],answer:1,explanation:"An MOU documents mutual understanding and expectations, often used before a formal contract or for partner security agreements.",optionExplanations:["A legally binding contract carries formal legal remedies, whereas an MOU is typically non-binding by design.","An MOU establishes mutual expectations between parties without full legal enforceability, often used to formalize partnerships.","Technical configuration documents specify system settings, while an MOU instead defines organizational relationships and expectations.","Invoices are financial billing documents, entirely distinct from an MOU's role of defining a relationship and expectations."]},
  {id:276,domain:G,question:"What is the difference between synchronous and asynchronous encryption?",options:["Synchronous and asynchronous encryption are interchangeable terms both describing symmetric block cipher algorithms that operate on fixed-length data blocks","Synchronous encryption uses a shared clock signal synchronized between sender and receiver, while asynchronous encryption transmits data with start and stop framing bits","Synchronous encryption refers to stream ciphers that operate in sync with a clock/keystream; asynchronous is not a standard cryptographic term","Asynchronous encryption consistently achieves higher throughput and performance than synchronous algorithms by eliminating the need for keystream clock synchronization"],answer:2,explanation:"In some contexts, synchronous stream ciphers maintain an independent keystream; 'asynchronous' is not standard terminology in cryptography.",optionExplanations:["They are not interchangeable standard terms; synchronous refers to stream ciphers synchronized with a keystream, while asynchronous is not a recognized standard cryptographic classification.","This conflates data transmission terminology with cryptographic modes; synchronous in cryptography refers to stream ciphers tied to a keystream, not clock signaling between parties.","Synchronous stream ciphers generate keystreams independently; asynchronous is not a standardized cryptographic term.","Asynchronous is not a standard cryptographic performance category; performance differences exist between stream and block ciphers, but asynchronous encryption is not a recognized cryptographic term."]},
  {id:277,domain:G,question:"What is the purpose of a TPM (Trusted Platform Module)?",options:["Authenticate remote network users through RADIUS or TACACS+ challenge-response protocols managed by a centralized network access server","A hardware chip that stores cryptographic keys and enables platform integrity measurement","Protect data transmitted between client devices and network gateways using TLS encryption negotiated through a security appliance","Scan fingerprints or capture facial geometry to verify user identity through biometric authentication before granting system access"],answer:1,explanation:"A TPM securely stores encryption keys, performs cryptographic operations, and attests to the integrity of the boot process.",optionExplanations:["RADIUS/TACACS+ provide network authentication via dedicated servers; a TPM is a local hardware chip on the device itself that stores keys and provides platform integrity measurement.","The TPM is a dedicated security chip providing secure key storage, random number generation, and secure boot attestation.","TLS encryption protects network traffic using software protocols; a TPM is a hardware chip that stores cryptographic keys and measures system integrity at the platform level.","Biometric readers are user verification sensors; a TPM is a hardware security chip that stores keys and measures platform integrity to detect boot-level tampering, not identify users biometrically."]},
  {id:278,domain:G,question:"Which type of encryption is used in HTTPS for the initial key exchange?",options:["Symmetric encryption","Asymmetric encryption","Hashing","No encryption during handshake"],answer:1,explanation:"TLS uses asymmetric encryption (RSA or ECDHE) during the handshake to securely exchange the symmetric session key.",optionExplanations:["Symmetric encryption is used after the handshake for bulk data; asymmetric secures the key exchange.","Asymmetric encryption (or key agreement) establishes the shared symmetric session key during the TLS handshake.","Hashing provides integrity (HMAC) in TLS; it does not establish the session key.","TLS always encrypts the handshake parameters; the entire session is encrypted."]},
  {id:279,domain:G,question:"What is a supplicant in 802.1X authentication?",options:["The RADIUS server that authenticates users","The switch or AP that forwards authentication traffic","The client device requesting network access","The certificate authority issuing client certificates"],answer:2,explanation:"In 802.1X, the supplicant is the client (user's device) requesting access; the authenticator is the switch/AP; the auth server is RADIUS.",optionExplanations:["The RADIUS server is the authentication server, not the supplicant.","The switch or wireless AP is the authenticator (the middle component), not the supplicant.","The supplicant is the client device requesting network access through the 802.1X framework.","The CA issues certificates used by the supplicant and auth server; it is not a role in the 802.1X exchange."]},
  {id:280,domain:G,question:"What is a session key?",options:["A long-term permanent encryption key kept securely stored inside a hardware security module","A temporary symmetric key created for a single communication session","A dedicated signing key used exclusively by a CA to sign digital certificates","The long-term private key that is permanently bound to a PKI certificate"],answer:1,explanation:"Session keys are ephemeral symmetric keys negotiated for each session, providing both speed (symmetric) and forward secrecy (temporary).",optionExplanations:["Permanent keys stored in HSMs are long-term keys meant to persist, unlike the short-lived nature of a session key.","A session key is a temporary symmetric key generated fresh for each session, ensuring efficient encryption and forward secrecy.","Certificate signing uses the CA's long-term private key, whereas a session key is used to encrypt the session's actual data.","A PKI private key is the long-term asymmetric key tied to an identity, while a session key is symmetric and ephemeral."]},
  {id:281,domain:T,question:"What is an ARP spoofing attack?",options:["Intercepting DNS queries in transit and returning forged responses to redirect victims","Sending fake ARP messages to associate the attacker's MAC address with a legitimate IP","Flooding a switch's address table with an overwhelming volume of fake MAC addresses","Impersonating a legitimate DHCP server to hand out malicious network configuration settings"],answer:1,explanation:"ARP spoofing poisons ARP caches on the LAN so traffic destined for a legitimate IP is sent to the attacker's MAC address.",optionExplanations:["Intercepting DNS queries and returning forged responses describes DNS spoofing, a different attack from ARP spoofing.","ARP spoofing sends gratuitous ARP replies linking the attacker's MAC to a victim's IP, enabling traffic interception.","Flooding a switch's MAC table describes a MAC flooding attack, which forces the switch into hub-like broadcast mode, a distinct technique from ARP spoofing.","Impersonating a DHCP server describes a DHCP spoofing attack, a related but separate LAN attack from ARP spoofing."]},
  {id:282,domain:T,question:"What is a MAC flooding attack?",options:["Sending malicious executable payloads embedded directly within crafted network packets","Overwhelming a switch's MAC address table to force it to broadcast all frames","Spoofing a single trusted MAC address to bypass port-based authentication controls","Intercepting and replaying wireless MAC-based authentication handshakes to gain network access"],answer:1,explanation:"MAC flooding exhausts the CAM table, causing the switch to flood all traffic to all ports like a hub, enabling eavesdropping.",optionExplanations:["Delivering malware through network packets is a different delivery mechanism entirely from overwhelming a switch's address table.","MAC flooding sends massive quantities of frames with fake MACs, filling the CAM table and causing the switch to forward all traffic to all ports.","Spoofing a single MAC address to bypass authentication is a targeted impersonation technique, distinct from overwhelming the switch's entire table.","Intercepting wireless MAC authentication targets Wi-Fi access control, whereas MAC flooding specifically targets a wired switch's CAM table."]},
  {id:283,domain:T,question:"What is DHCP spoofing?",options:["Flooding the legitimate DHCP server with an overwhelming volume of bogus lease requests until its address pool is exhausted","An attacker acting as a rogue DHCP server to assign clients false network settings including a malicious gateway","Deliberately blocking all DHCP traffic at the network perimeter using explicitly configured firewall and access control rules","Passively scanning the local network segment to discover and catalog all currently active DHCP servers present"],answer:1,explanation:"A rogue DHCP server assigns attacker-controlled gateway IPs, routing all client traffic through the attacker.",optionExplanations:["Flooding the DHCP server with requests describes a DHCP starvation attack, which exhausts the address pool rather than serving false configuration.","A rogue DHCP server assigns attacker-controlled gateway IPs, routing all client traffic through the attacker.","Blocking DHCP traffic is a defensive firewall or DHCP snooping function, not an attack technique like spoofing.","Scanning for DHCP servers is passive reconnaissance, a precursor activity distinct from actually spoofing DHCP responses."]},
  {id:284,domain:T,question:"What is an SSL stripping attack?",options:["Removing SSL certificates from a server","Downgrading an HTTPS connection to HTTP by intercepting the initial redirect","Stealing SSL private keys","Replacing an SSL certificate with a self-signed one"],answer:1,explanation:"SSL stripping intercepts the HTTP-to-HTTPS redirect and maintains an unencrypted connection with the victim while HTTPS is used with the server.",optionExplanations:["Removing certificates from servers would break HTTPS; SSL stripping is an active interception attack.","SSL stripping intercepts the HTTP redirect to HTTPS, maintaining unencrypted communication with the victim while connecting to the server via HTTPS.","Private key theft is a PKI compromise; SSL stripping doesn't require obtaining keys.","Certificate substitution is a MITM via fraudulent certificates; SSL stripping avoids encryption entirely for the victim connection."]},
  {id:285,domain:T,question:"Which of the following BEST describes a cross-site scripting (XSS) attack?",options:["Injecting SQL commands into web form fields","Injecting malicious scripts into web pages that execute in other users' browsers","Intercepting traffic between web servers","Exploiting a buffer overflow in a web server"],answer:1,explanation:"XSS injects client-side scripts (JavaScript) into pages served to other users, executing in their browser's security context.",optionExplanations:["SQL injection targets database queries; XSS targets the browser's script execution.","XSS embeds malicious JavaScript into web pages, executing in victims' browsers to steal cookies, redirect, or perform actions.","Traffic interception is MITM; XSS is an injection attack at the application layer.","Buffer overflows target server memory; XSS targets client browsers through injected scripts."]},
  {id:286,domain:A,question:"What is a security zone in network architecture?",options:["A geographic area where security cameras are deployed","A defined network segment with specific trust level and associated security controls","A VLAN reserved for security tools","A subnet for DMZ servers only"],answer:1,explanation:"Security zones partition the network by trust level (trusted, untrusted, DMZ) and apply appropriate controls at zone boundaries.",optionExplanations:["Camera deployment areas are physical security zones; network security zones are logical partitions.","Security zones define trust levels for network segments with firewalls and controls enforced at zone boundaries.","VLANs for security tools are a configuration detail; security zones are an architectural concept.","DMZ is one type of security zone; others include trusted internal, untrusted external, and partner zones."]},
  {id:287,domain:A,question:"What is the purpose of subnetting in network security?",options:["Increase network speed","Divide a large network into smaller, more manageable and isolated segments","Provide wireless access","Assign MAC addresses to devices"],answer:1,explanation:"Subnetting creates smaller network segments that limit broadcast domains and can restrict traffic flow between segments.",optionExplanations:["Subnetting doesn't directly increase speed; it improves manageability and security through isolation.","Subnetting divides large IP address spaces into smaller segments, reducing broadcast domains and enabling traffic control.","Wireless access is provided by access points; subnetting is IP network segmentation.","MAC addresses are burned into hardware (Layer 2); IP subnetting operates at Layer 3."]},
  {id:288,domain:A,question:"What is the role of an HSM in a PKI?",options:["Issue digital certificates to end users","Securely generate and store the CA's private key, protecting it from extraction","Provide a web portal for certificate requests","Revoke compromised certificates"],answer:1,explanation:"An HSM stores the CA's private key in tamper-resistant hardware, ensuring it cannot be extracted even if the CA server is compromised.",optionExplanations:["Certificate issuance is the CA software function; the HSM just protects the private key used to sign them.","An HSM provides hardware protection for the CA's private key, making it resistant to extraction and software-based attacks.","Certificate request portals (web interfaces) are CA application features, not HSM functions.","Certificate revocation is managed by the CA software through CRLs and OCSP; the HSM protects the signing key."]},
  {id:289,domain:A,question:"What is meant by 'resilience' in security architecture?",options:["The ability to prevent all attacks","The ability to continue operating and recover quickly despite attacks, failures, or disasters","Using redundant security tools","Having the fastest possible systems"],answer:1,explanation:"Security resilience means systems can withstand or recover from disruptions without unacceptable loss of functionality.",optionExplanations:["No architecture can prevent all attacks; resilience focuses on surviving and recovering from them.","Resilience is the capacity to absorb disruptions, maintain essential functions, and recover with minimal impact.","Redundant tools contribute to resilience but are not its complete definition.","Speed matters for performance; resilience is about continuity and recovery."]},
  {id:290,domain:A,question:"What is the purpose of a web application firewall (WAF)?",options:["Filter network traffic at Layer 3","Inspect and filter HTTP/S traffic to protect web applications from attacks like SQLi and XSS","Provide SSL/TLS encryption for web servers","Monitor server performance"],answer:1,explanation:"A WAF analyzes HTTP/S requests and responses against security policies to block web application attacks.",optionExplanations:["Layer 3 filtering is done by traditional firewalls using IP addresses; WAFs operate at Layer 7.","WAFs inspect HTTP application traffic, detecting and blocking OWASP Top 10 attacks including SQLi, XSS, and CSRF.","SSL/TLS encryption is provided by the server or load balancer's TLS configuration; WAFs may perform TLS offloading.","Server performance monitoring is done by APM tools; WAFs focus on security inspection of application traffic."]},
  {id:291,domain:O,question:"What is the concept of 'dwell time' in security?",options:["The time a security analyst spends investigating an alert","The length of time an attacker remains undetected inside a network after compromising it","The time it takes to recover from an incident","The duration of a security audit"],answer:1,explanation:"Dwell time (breakout time) is how long attackers lurk undetected; reducing it is a key goal of threat hunting and detection.",optionExplanations:["Analyst investigation time is MTTR-related; dwell time is about attacker persistence before detection.","Dwell time measures how long an attacker has been inside the network without being detected — a key indicator of detection effectiveness.","Recovery time is measured by MTTR; dwell time is pre-detection persistence.","Audit duration is a planning parameter; dwell time is a security metric."]},
  {id:292,domain:O,question:"What is the purpose of threat modeling?",options:["Scan systems for vulnerabilities","Identify and prioritize potential threats against a system or application during the design phase","Train developers in secure coding","Deploy firewalls based on identified threats"],answer:1,explanation:"Threat modeling (STRIDE, PASTA, LINDDUN) systematically identifies threats early in design to guide security controls.",optionExplanations:["Vulnerability scanning tests live systems; threat modeling is a design-time analysis activity.","Threat modeling analyzes potential adversaries, threats, and weaknesses during design to enable proactive security controls.","Secure coding training is security education; threat modeling is a structured analysis methodology.","Firewall deployment results from threat model findings; the threat model itself is the analysis process."]},
  {id:293,domain:O,question:"What is the purpose of a security kernel?",options:["The core security component of a hardware security module","A minimal, trusted portion of an OS that implements and enforces all security policies","A vulnerability in the OS kernel","A dedicated server running security tools"],answer:1,explanation:"A security kernel is the smallest, most trusted portion of an OS — typically the TCB — that enforces all access control decisions.",optionExplanations:["HSM hardware components are not called security kernels.","The security kernel is the trusted core of an OS that implements mandatory security policies and cannot be bypassed.","A kernel vulnerability is a CVE in OS code; a security kernel is a security architecture concept.","A dedicated security server runs tools; a security kernel is an OS design concept."]},
  {id:294,domain:O,question:"What is the difference between active and passive vulnerability scanning?",options:["Active scans are manual; passive are automated","Active scanning probes systems directly; passive scanning analyzes captured network traffic without direct probing","Active scans find more vulnerabilities; passive finds fewer","Passive scans are invasive; active scans are not"],answer:1,explanation:"Active scanning sends probes to systems; passive scanning observes traffic to infer vulnerabilities without touching target systems.",optionExplanations:["Both active and passive scanning can be automated.","Active scanning directly queries systems (Nessus, OpenVAS); passive scanning observes traffic without touching targets.","Both types can find significant vulnerabilities; coverage differs by type.","Active scanning can be invasive (it probes systems); passive scanning is non-invasive."]},
  {id:295,domain:O,question:"What is a vulnerability scoring system (CVSS)?",options:["A list of all known CVEs","A standardized framework for rating the severity of vulnerabilities using metrics like exploitability and impact","A database of vendor patch releases","A tool for scanning systems for vulnerabilities"],answer:1,explanation:"CVSS (Common Vulnerability Scoring System) provides 0-10 severity scores based on exploitability, scope, and impact metrics.",optionExplanations:["The CVE list catalogs vulnerabilities by ID; CVSS scores their severity.","CVSS assigns a numeric severity score based on factors like attack vector, complexity, privileges required, and impact.","Patch databases track vendor releases; CVSS scores severity of the vulnerabilities they address.","Scanning tools like Nessus report CVSS scores but are not the scoring system itself."]},
  {id:296,domain:P,question:"What is a system security plan (SSP)?",options:["A daily security monitoring schedule","A formal document describing a system's security requirements, controls, and their implementation","A software testing plan","A backup recovery procedure"],answer:1,explanation:"An SSP (required by NIST and FISMA) documents a system's security environment, control implementations, and responsibilities.",optionExplanations:["Monitoring schedules are operational procedures; an SSP is a comprehensive security documentation artifact.","An SSP documents security controls implemented on a system, their status, responsible parties, and operational environment.","Software test plans describe testing approaches for software quality; SSPs document security control implementation.","Backup procedures are disaster recovery documents; an SSP is a security documentation requirement."]},
  {id:297,domain:P,question:"What is the purpose of an audit trail in security?",options:["Prevent unauthorized access","A chronological record of events and actions enabling accountability and forensic investigation","Encrypt activity logs","Automatically respond to security events"],answer:1,explanation:"An audit trail is an immutable log of events providing accountability, supporting investigations and demonstrating compliance.",optionExplanations:["Preventing unauthorized access is the role of access controls; audit trails record what happened.","An audit trail records who did what, when, and from where — providing accountability and forensic reconstruction.","Log encryption is a protective control for the audit trail itself; the trail is the record.","Automated response is SOAR; audit trails are the evidence record used to inform response."]},
  {id:298,domain:P,question:"What is the concept of 'privacy by design'?",options:["Adding privacy controls after a system is built","Incorporating privacy protections into systems from the initial design phase rather than as an afterthought","Encrypting all personal data","Conducting annual privacy audits"],answer:1,explanation:"Privacy by design (Ann Cavoukian) integrates privacy as a core requirement from the start, not bolted on later.",optionExplanations:["Adding privacy controls after building a system is 'privacy by retrofit,' which is less effective.","Privacy by design embeds privacy principles (data minimization, purpose limitation) into architecture from the beginning.","Encryption is one privacy technical control; privacy by design is a holistic design philosophy.","Annual audits are compliance verification; privacy by design is about proactive integration of privacy."]},
  {id:299,domain:P,question:"What does the term 'data sovereignty' mean?",options:["The right to access any data on the internet","Data is subject to the laws and governance of the country where it is stored or processed","Organizations own all data they collect","Data must be encrypted regardless of location"],answer:1,explanation:"Data sovereignty means data stored in a country is subject to that country's laws, affecting where organizations can store data.",optionExplanations:["Internet access rights are a separate concept; data sovereignty is about legal jurisdiction.","Data sovereignty recognizes that data stored in a country falls under that nation's legal jurisdiction and regulations.","Data ownership rights depend on contracts and privacy law; data sovereignty is about legal jurisdiction.","Encryption requirements vary by regulation; data sovereignty is about jurisdictional control, not encryption specifically."]},
  {id:300,domain:P,question:"What is a security charter?",options:["A firewall rule set","A document defining the authority, scope, responsibilities, and goals of the security program","A penetration test authorization form","A network security policy"],answer:1,explanation:"A security charter grants the CISO and security program formal authority, defines scope, and establishes organizational accountability.",optionExplanations:["Firewall rule sets are technical access control documents; a charter establishes organizational authority.","A security charter formalizes the security program's mandate, authority, and responsibilities within the organization.","Pen test authorization is a rules of engagement document; a charter is a broader program mandate.","Security policies define rules; a charter establishes the program's authority to create and enforce those policies."]},
  {id:301,domain:G,question:"What is the purpose of a time-based one-time password (TOTP)?",options:["Replace all other authentication methods","Generate a short-lived password based on the current time and a shared secret, valid for ~30 seconds","Store passwords securely in the cloud","Provide single sign-on capabilities"],answer:1,explanation:"TOTP (RFC 6238) generates a new 6-digit code every 30 seconds using HMAC-SHA1 and the current timestamp.",optionExplanations:["TOTP is typically used as a second factor, not a replacement for all authentication.","TOTP combines the current Unix time with a shared secret using HMAC to generate a short-lived code.","Password storage is handled by password managers and vaults; TOTP generates temporary codes.","SSO allows one login across systems; TOTP is a single authentication factor."]},
  {id:302,domain:G,question:"Which of the following BEST describes a hardware OTP token?",options:["A USB drive storing passwords","A physical device that generates one-time passwords without requiring network connectivity","A smart card used for digital signatures","A biometric fingerprint reader"],answer:1,explanation:"Hardware tokens (RSA SecurID, YubiKey OTP) generate time or counter-based OTPs without network or battery in some models.",optionExplanations:["USB drives store files; hardware OTP tokens generate dynamic codes.","Hardware OTP tokens are self-contained devices generating fresh codes for each authentication, independent of network access.","Smart cards store certificates and private keys for digital signatures; OTP tokens generate numeric codes.","Fingerprint readers capture biometric data; OTP tokens are knowledge/possession factors."]},
  {id:303,domain:T,question:"What is a golden ticket attack in Active Directory?",options:["A phishing attack using fake Microsoft emails","Forging a Kerberos TGT using the KRBTGT account hash, granting access to any resource in the domain","A physical access attack on domain controllers","An LDAP injection attack"],answer:1,explanation:"By compromising the KRBTGT hash, attackers create forged TGTs valid for any account and resource, granting domain-wide persistence.",optionExplanations:["Microsoft-themed phishing is a social engineering attack, not a Kerberos attack.","A golden ticket is a forged Kerberos TGT created with the KRBTGT account's NTLM hash, granting unlimited domain access.","Physical DC attacks are separate; golden tickets are forged authentication tokens.","LDAP injection targets directory service queries; golden tickets exploit Kerberos authentication."]},
  {id:304,domain:T,question:"What is a silver ticket attack?",options:["A golden ticket with limited scope","Forging a Kerberos service ticket for a specific service without contacting the KDC","Stealing NTLM hashes from memory","A replay attack against Kerberos"],answer:1,explanation:"Silver tickets forge Kerberos service tickets using a service account's hash, granting access to a specific service without KDC involvement.",optionExplanations:["Silver tickets are related to golden tickets but target specific services, not domain-wide access.","A silver ticket forges a service ticket using the service account hash, enabling access to that specific service without KDC logging.","Stealing NTLM hashes is credential harvesting; silver tickets use those hashes to forge service tickets.","Replay attacks reuse captured authentication data; silver tickets are forged from scratch."]},
  {id:305,domain:T,question:"What is lateral movement in a cyberattack?",options:["Increasing the bandwidth of an attack","Spreading from the initial compromised system to other systems within the network","Exfiltrating data to an external server","Escalating privileges on the initial compromised host"],answer:1,explanation:"Lateral movement uses techniques like pass-the-hash, RDP, and SSH to move from the beachhead to other targets in the network.",optionExplanations:["Bandwidth is a network capacity metric; lateral movement is an attacker technique.","Lateral movement expands the attacker's foothold across the network from the initial compromised system.","Data exfiltration is the final objective; lateral movement is the technique used to reach valuable targets first.","Privilege escalation gains higher access on one system; lateral movement spreads across multiple systems."]},
  {id:306,domain:A,question:"What is micro-segmentation and how does it differ from traditional segmentation?",options:["Micro-segmentation uses smaller VLANs; traditional uses larger ones","Micro-segmentation applies policies at the individual workload level; traditional uses zone-level segmentation with firewalls","They are the same concept","Traditional segmentation uses software; micro-segmentation uses hardware"],answer:1,explanation:"Micro-segmentation enforces policies per workload/VM using software-defined controls, much more granular than VLAN-based zone segmentation.",optionExplanations:["Size of VLANs is not the defining difference.","Micro-segmentation applies security policies to individual workloads or containers, limiting east-west movement far more granularly than traditional zones.","They address the same problem (isolation) at different granularity levels.","Micro-segmentation is typically software-defined; it doesn't require physical hardware per workload."]},
  {id:307,domain:A,question:"What security concern is associated with shadow IT?",options:["IT staff working overtime without authorization","Employees using unauthorized cloud apps or devices, creating uncontrolled risk exposure outside security policies","Unpatched legacy systems","Security software running without management approval"],answer:1,explanation:"Shadow IT bypasses corporate security controls, potentially exposing sensitive data and creating compliance violations.",optionExplanations:["Overtime is an HR matter; shadow IT is unauthorized technology use.","Shadow IT introduces uncontrolled risk because unauthorized apps lack corporate security review, monitoring, and data governance.","Legacy system patches are vulnerability management; shadow IT is about unsanctioned technology adoption.","Security software approval is an IT governance issue; shadow IT encompasses all unauthorized technology use."]},
  {id:308,domain:A,question:"What is the purpose of network flow monitoring (NetFlow)?",options:["Capture complete network packet content","Analyze metadata about network conversations (source/destination, port, bytes, duration) to detect anomalies","Filter malicious network traffic","Encrypt network traffic between devices"],answer:1,explanation:"NetFlow/IPFIX captures flow records (metadata only) enabling traffic pattern analysis and anomaly detection at scale.",optionExplanations:["Full packet capture is done by sniffers like Wireshark; NetFlow captures flow metadata only.","NetFlow records capture traffic metadata — 5-tuple, byte counts, timestamps — enabling anomaly detection without storing full packets.","Traffic filtering is done by firewalls and IPS; NetFlow is a monitoring and analysis tool.","Traffic encryption is done by protocols like TLS; NetFlow analyzes the resulting traffic patterns."]},
  {id:309,domain:O,question:"What is the purpose of endpoint hardening?",options:["Install more applications on endpoints","Remove unnecessary services, disable unused ports, and configure security settings to minimize the attack surface","Add more users to administrator groups","Increase endpoint performance"],answer:1,explanation:"Endpoint hardening reduces attack surface by removing default accounts, disabling unneeded services, and applying security baselines.",optionExplanations:["Installing more applications increases attack surface; hardening reduces it.","Endpoint hardening applies CIS benchmark configurations — disabling unused services, restricting privileges, enabling logging.","Adding users to admin groups violates least privilege; hardening enforces minimum necessary access.","Hardening may reduce performance slightly; security takes priority."]},
  {id:310,domain:O,question:"What is a known-good baseline in security?",options:["A list of known malware signatures","A documented snapshot of a system's normal, secure state used for comparison to detect changes","The highest security configuration possible","A network topology diagram"],answer:1,explanation:"A known-good baseline enables integrity monitoring — any deviation indicates unauthorized change or compromise.",optionExplanations:["Malware signatures are detection databases; a baseline documents normal system state.","A known-good baseline captures expected system configuration, files, and behavior to detect unauthorized modifications.","Maximum security configuration is a hardening target; a baseline is the documented normal state.","Network topology documents network connections; a system baseline documents system configuration state."]},
  {id:311,domain:P,question:"Which regulation requires organizations to report data breaches to affected individuals within 72 hours?",options:["HIPAA","PCI DSS","GDPR","SOX"],answer:2,explanation:"GDPR Article 33 requires notifying the supervisory authority within 72 hours of becoming aware of a data breach.",optionExplanations:["HIPAA breach notification requires notification to individuals within 60 days; supervisory authority within 72 hours is GDPR.","PCI DSS requires incident reporting to card brands but does not specify a 72-hour timeline to individuals.","GDPR requires supervisory authority notification within 72 hours and individual notification without undue delay.","SOX focuses on financial reporting accuracy for publicly traded companies, not data breach notification timelines."]},
  {id:312,domain:P,question:"What is the purpose of a data processing agreement (DPA)?",options:["License software for data analytics","A legally binding contract governing how a data processor handles personal data on behalf of a controller","An internal policy for data retention","A technical specification for data encryption"],answer:1,explanation:"DPAs (required under GDPR) define the processor's obligations for processing personal data on behalf of the controller.",optionExplanations:["Software licensing is handled by EULAs and software contracts; DPAs govern data processing relationships.","A DPA establishes legal obligations between data controllers and processors, required by GDPR for all processing relationships.","Internal data retention policies are administrative documents; DPAs are binding contracts with third parties.","Technical encryption specs are implementation standards; DPAs define legal obligations and responsibilities."]},
  {id:313,domain:P,question:"What is the concept of 'data minimization' in privacy?",options:["Using smaller data files to save storage","Collecting only the minimum personal data necessary for the specified purpose","Deleting data after processing","Encrypting personal data"],answer:1,explanation:"Data minimization (a GDPR principle) means collecting only what is strictly necessary, reducing privacy risk.",optionExplanations:["File size reduction is data compression; data minimization is about limiting collection scope.","Data minimization collects only data that is adequate, relevant, and limited to what is necessary for the stated purpose.","Data deletion is related to retention limits; minimization is about limiting collection from the start.","Encryption protects data; minimization reduces the amount of data at risk."]},
  {id:314,domain:O,question:"What is a security operations maturity model?",options:["A measure of how many security tools are deployed","A framework assessing the sophistication and effectiveness of a security operations program across capability levels","A list of security certifications held by the team","A benchmark for security tool performance"],answer:1,explanation:"SOC maturity models (like the SOC-CMM) assess capabilities from ad hoc (Level 1) to optimized, metrics-driven programs (Level 5).",optionExplanations:["Tool count is a vanity metric; maturity measures capability and process sophistication.","Security maturity models assess people, process, and technology capabilities across progressive maturity levels.","Certifications held by staff are an input; maturity models assess organizational capabilities.","Tool benchmarks measure technical performance; maturity models assess overall program effectiveness."]},
  {id:315,domain:T,question:"What is a living-off-the-land (LotL) attack?",options:["An attack on agricultural systems","Using legitimate system tools (PowerShell, WMI, Certutil) already present on the target to carry out malicious activity","A type of supply chain attack","Hiding malware in environmental data"],answer:1,explanation:"LotL attacks use built-in OS tools to blend in with normal activity, evading detection by not dropping external malware.",optionExplanations:["Agricultural systems are OT/ICS targets; LotL is an endpoint attack technique.","LotL attacks use trusted, pre-installed tools (certutil, mshta, regsvr32) for malicious purposes, evading file-based detection.","Supply chain attacks compromise vendors; LotL uses tools already present on compromised systems.","Environmental data hiding is not a cyberattack category; LotL is about using system tools maliciously."]},
  {id:316,domain:T,question:"What is a pass-the-ticket attack?",options:["A replay attack against web session cookies","Using a stolen Kerberos ticket to authenticate as the ticket's owner without knowing their password","Stealing Kerberos service account passwords","A brute force attack against Kerberos authentication"],answer:1,explanation:"Pass-the-ticket extracts Kerberos tickets from memory (using Mimikatz) and reuses them to authenticate to services.",optionExplanations:["Web session cookie replay is session hijacking; Kerberos tickets are different authentication artifacts.","Pass-the-ticket uses extracted Kerberos TGT or service tickets to authenticate without needing the account password.","Stealing passwords is credential harvesting; pass-the-ticket uses the ticket directly.","Brute force guesses passwords; pass-the-ticket reuses a valid, already-issued ticket."]},
  {id:317,domain:A,question:"What is a network tap?",options:["A firewall rule that copies traffic","A hardware device passively copying all traffic on a network link for monitoring without introducing latency","A wireless access point for testing","A software tool for analyzing PCAP files"],answer:1,explanation:"A network tap passively copies traffic off a link (optical or electrical) to a monitoring device without affecting the original traffic.",optionExplanations:["Firewall rules that copy traffic are port mirroring configurations; a tap is hardware-based.","A network tap is a passive hardware device that copies all traffic on a link to monitoring tools without adding latency or risk of packet loss.","Wireless access points provide network connectivity; taps are physical network monitoring hardware.","PCAP analysis tools (Wireshark) analyze captured traffic; a tap is the hardware that captures it."]},
  {id:318,domain:A,question:"What is SPAN (Switched Port Analyzer)?",options:["A network security protocol","A switch feature that copies traffic from one or more ports to a designated monitoring port","A wireless monitoring tool","A firewall traffic inspection mode"],answer:1,explanation:"SPAN (port mirroring) configures a switch to copy frames from selected ports to a monitoring port for analysis by IDS/sniffers.",optionExplanations:["SPAN is a switch feature, not a network protocol.","SPAN configures a switch to mirror traffic from source ports to a destination monitoring port for network analysis.","Wireless monitoring uses separate tools; SPAN is a wired switch capability.","Firewall inspection analyzes traffic passing through it; SPAN provides a copy of traffic for external analysis."]},
  {id:319,domain:O,question:"What is the purpose of a post-incident review (lessons learned)?",options:["Assign blame for the incident","Analyze what happened, identify what worked and what didn't, and improve processes for the future","Document legal evidence","Close the incident in the ticketing system"],answer:1,explanation:"Post-incident reviews identify root causes, process improvements, and control gaps to strengthen defenses against future incidents.",optionExplanations:["Blame assignment is counterproductive; lessons learned focus on systemic improvements.","Post-incident reviews analyze the timeline, root cause, response effectiveness, and control gaps to improve future response.","Legal evidence documentation is part of chain of custody; lessons learned focus on improvement.","Ticket closure is an administrative step; lessons learned drive meaningful security improvements."]},
  {id:320,domain:O,question:"What is the role of the incident response team (IRT)?",options:["Perform annual penetration tests","Coordinate the technical and managerial response to security incidents from detection through recovery","Manage day-to-day IT operations","Train employees on security awareness"],answer:1,explanation:"The IRT (or CSIRT/CERT) detects, analyzes, contains, eradicates, and recovers from security incidents.",optionExplanations:["Annual pen tests are conducted by red teams or third-party pentesters; IRT handles live incidents.","The incident response team coordinates all aspects of incident handling from initial detection through final recovery and lessons learned.","Day-to-day IT operations are managed by IT operations teams; IRT handles security incidents.","Security awareness training is delivered by HR and the security program; IRT focuses on incident handling."]},
  {id:321,domain:G,question:"What is the purpose of a pre-shared key (PSK) in Wi-Fi security?",options:["Dynamically generate unique keys per user","A shared password used by all devices to authenticate and derive encryption keys for the wireless network","Provide certificate-based authentication","Encrypt only management frames"],answer:1,explanation:"PSK (used in WPA2/WPA3 Personal) is a shared passphrase all devices use; enterprise networks use 802.1X instead.",optionExplanations:["Dynamic unique keys per user require 802.1X enterprise authentication, not PSK.","A PSK is a shared passphrase configured on the AP and all client devices, deriving the encryption key from it.","Certificate-based authentication is used in WPA2/WPA3 Enterprise with 802.1X, not PSK mode.","Management frame protection (802.11w) is separate; PSK protects data frame encryption keys."]},
  {id:322,domain:G,question:"What is the purpose of a Kerberos KDC?",options:["Issue TLS certificates to clients","Issue Ticket Granting Tickets and service tickets enabling authenticated access without transmitting passwords","Manage LDAP directory queries","Provide network address translation"],answer:1,explanation:"The Key Distribution Center (KDC) contains the Authentication Server (AS) and Ticket Granting Server (TGS) for Kerberos.",optionExplanations:["TLS certificates are issued by Certificate Authorities; the KDC issues Kerberos tickets.","The KDC issues TGTs to authenticated users and service tickets for specific services, without ever sending passwords over the network.","LDAP directory services are separate; the KDC uses the directory for account information but has its own ticket-issuing function.","NAT translates IP addresses; the KDC manages cryptographic authentication tickets."]},
  {id:323,domain:T,question:"What is the purpose of network reconnaissance tools like Nmap?",options:["Encrypt network traffic","Discover hosts, open ports, and services on a network for security assessment or attack planning","Block malicious traffic","Provide VPN connectivity"],answer:1,explanation:"Nmap is a network scanner used to discover live hosts, open ports, running services, and OS fingerprints.",optionExplanations:["Nmap does not encrypt traffic; it probes systems to discover what is running.","Nmap discovers network topology, open ports, service versions, and OS details — essential for both defense and offense.","Firewalls and IPS block traffic; Nmap is a discovery tool.","VPN tools create encrypted tunnels; Nmap is a network discovery and scanning tool."]},
  {id:324,domain:T,question:"What is a credential harvesting attack?",options:["Brute forcing login pages","Tricking users into entering their credentials on a fake site or through other means to steal them","Cracking stored password hashes","Generating default credentials for IoT devices"],answer:1,explanation:"Credential harvesting tricks users into submitting credentials to attacker-controlled pages through phishing, fake sites, or malware.",optionExplanations:["Brute force systematically guesses credentials; harvesting tricks users into providing them voluntarily.","Credential harvesting steals credentials through deception (phishing pages, fake login forms) rather than technical cracking.","Hash cracking is an offline attack against stolen password databases; harvesting captures credentials in plaintext.","Default credential generation is a configuration attack; harvesting captures real user credentials."]},
  {id:325,domain:A,question:"What is the purpose of rate limiting in web security?",options:["Speed up web server responses","Restrict the number of requests from a single source in a time window to prevent abuse, DoS, or brute force","Encrypt API responses","Log all incoming requests"],answer:1,explanation:"Rate limiting prevents brute force, credential stuffing, and API abuse by limiting how many requests a client can make per unit time.",optionExplanations:["Rate limiting slows requests from any single source; it does not speed up server responses.","Rate limiting caps request frequency to prevent password brute force, scraping, and API-based DoS attacks.","Response encryption is handled by TLS; rate limiting is about request frequency control.","Logging is done by the web server and SIEM; rate limiting is an active control mechanism."]},
  {id:326,domain:P,question:"Which of the following is a primary security control objective of HIPAA Security Rule?",options:["Encryption of all email","Ensure the confidentiality, integrity, and availability of all ePHI","Require MFA for all users","Prohibit cloud storage of health data"],answer:1,explanation:"The HIPAA Security Rule requires covered entities to protect the CIA of all electronic protected health information.",optionExplanations:["HIPAA recommends but does not mandate email encryption as a specific required control.","The HIPAA Security Rule's overall objective is to ensure CIA of all ePHI through administrative, physical, and technical safeguards.","HIPAA does not specifically mandate MFA, though it is a recommended safeguard for access control.","HIPAA does not prohibit cloud storage; it requires any cloud storage to be covered by a Business Associate Agreement (BAA)."]},
  {id:327,domain:O,question:"What is the function of a security information broker?",options:["Buy and sell stolen data","Aggregate and normalize security data from multiple sources for analysis and correlation","Manage vendor security assessments","Provide threat intelligence exclusively"],answer:1,explanation:"A security data broker aggregates logs and events from multiple disparate systems into a common format for analysis.",optionExplanations:["Data brokers in the criminal context sell stolen data; security information brokers are legitimate aggregation tools.","A security information broker normalizes and aggregates security data from diverse sources to enable unified analysis.","Vendor assessments are third-party risk management activities, not a data broker function.","Threat intelligence is one input; a security information broker handles all types of security data."]},
  {id:328,domain:O,question:"What is the purpose of a continuous monitoring program?",options:["Conduct annual security assessments only","Maintain ongoing awareness of information security, vulnerabilities, and threats in real time","Train staff on security policies annually","Deploy security patches quarterly"],answer:1,explanation:"Continuous monitoring provides real-time or near-real-time visibility into security posture, replacing periodic point-in-time assessments.",optionExplanations:["Annual assessments are periodic snapshots; continuous monitoring provides ongoing visibility.","Continuous monitoring maintains persistent awareness of control effectiveness, new vulnerabilities, and threat indicators.","Annual training is part of the security program; continuous monitoring is an operational capability.","Quarterly patching is a patch management cadence; continuous monitoring detects vulnerabilities requiring patching."]},
  {id:329,domain:G,question:"What is the PBKDF2 algorithm used for?",options:["Generating asymmetric key pairs","Deriving cryptographic keys from passwords using salt and iteration count","Encrypting bulk data","Providing TLS session key exchange"],answer:1,explanation:"PBKDF2 (Password-Based Key Derivation Function 2) strengthens passwords by applying HMAC many times with a salt.",optionExplanations:["Asymmetric key pairs are generated by algorithms like RSA or ECDSA; PBKDF2 derives symmetric keys from passwords.","PBKDF2 takes a password, salt, iteration count, and desired key length, producing a strong cryptographic key.","Bulk data encryption uses symmetric ciphers like AES; PBKDF2 derives the key used for such encryption.","TLS session key exchange uses Diffie-Hellman or RSA; PBKDF2 is for password-based key derivation."]},
  {id:330,domain:T,question:"What is the purpose of obfuscation in malware?",options:["Improve malware performance","Make malware code harder to analyze and detect by security tools","Encrypt victim data","Spread malware more efficiently"],answer:1,explanation:"Malware obfuscation (encoding, packing, polymorphism) disguises code to evade signature-based detection and complicate reverse engineering.",optionExplanations:["Obfuscation adds overhead and may reduce performance; detection evasion is the goal.","Malware obfuscation techniques (base64 encoding, packing, string encryption) make analysis and signature detection harder.","Data encryption is what ransomware does to victim files; obfuscation hides the malware's own code.","Propagation uses network/removable media techniques; obfuscation is about evading analysis and detection."]},
  {id:331,domain:A,question:"What is network address translation (NAT) and how does it help security?",options:["It encrypts traffic between internal and external systems","It maps private internal IPs to a public IP, hiding internal network topology from external observers","It prevents all inbound connections by default","It provides authentication for network access"],answer:1,explanation:"NAT hides internal IP addressing from external attackers, reducing reconnaissance information about the internal network.",optionExplanations:["NAT translates addresses but does not encrypt traffic; VPNs and TLS provide encryption.","NAT hides the internal network structure by presenting a single public IP, making it harder for attackers to map internal topology.","NAT can be configured to block unsolicited inbound connections, but this is firewall behavior; NAT's primary purpose is address translation.","Authentication is provided by IAM and 802.1X; NAT is an address translation mechanism."]},
  {id:332,domain:A,question:"What is the purpose of 802.11w (Protected Management Frames)?",options:["Encrypt wireless data frames","Protect 802.11 management frames (deauth, disassoc) from spoofing and injection attacks","Increase wireless network speed","Provide WPA3 compatibility"],answer:1,explanation:"802.11w protects management frames so attackers cannot send fake deauthentication frames to disconnect clients.",optionExplanations:["Data frame encryption is provided by WPA2/WPA3 data encryption (CCMP, GCMP); 802.11w protects management frames.","802.11w (PMF) authenticates management frames preventing deauthentication attacks used to force client disconnections.","Management frame protection adds security overhead; it does not improve network speed.","802.11w is a Wi-Fi security extension; WPA3 mandates PMF, making WPA3 and 802.11w complementary."]},
  {id:333,domain:T,question:"What is a JPEG or PDF file used to deliver malware called?",options:["A rootkit","A malicious document or lure","A bootkit","A macro virus"],answer:1,explanation:"Malicious documents (maldocs) embed exploits or malicious macros in PDFs, Office files, or image metadata to deliver malware.",optionExplanations:["A rootkit is persistent malware hiding at the OS level; a malicious document is a delivery mechanism.","Maldocs are weaponized files (PDF exploits, Office macros) used to deliver malware when opened by victims.","A bootkit infects the MBR or boot process; malicious documents exploit document viewers and macro engines.","Macro viruses are a subset of maldocs; malicious documents include PDF exploits and image file exploits as well."]},
  {id:334,domain:O,question:"What is the purpose of network segmentation in limiting ransomware spread?",options:["Prevent ransomware from encrypting files","Limit how far ransomware can spread by restricting its ability to reach other network segments","Speed up ransomware recovery","Detect ransomware before it executes"],answer:1,explanation:"Segmentation limits ransomware's lateral movement, confining it to the segment where it first landed.",optionExplanations:["File encryption cannot be prevented by network segmentation alone — the infected system will still be encrypted.","Segmentation restricts ransomware from spreading across the entire network by limiting access between segments.","Recovery speed depends on backup quality and DR plans; segmentation limits the damage scope.","Detection is done by EDR and email gateways; segmentation limits spread after detection fails."]},
  {id:335,domain:P,question:"What is the concept of 'right to erasure' (right to be forgotten) under GDPR?",options:["Organizations must immediately delete all data on request","Individuals can request deletion of their personal data under certain conditions, and organizations must comply or provide legal grounds to refuse","It applies only to data held for more than 10 years","Only applies to financial data"],answer:1,explanation:"GDPR Article 17 grants individuals the right to request data deletion when data is no longer necessary or consent is withdrawn.",optionExplanations:["Organizations do not have to delete all data immediately; erasure rights have conditions and exceptions (legal obligations, public interest).","GDPR's right to erasure allows data subjects to request deletion under specific conditions; organizations may refuse with legal justification.","GDPR's retention and erasure principles are not limited to data held beyond a specific time period.","GDPR covers all categories of personal data, not only financial data."]},
  {id:336,domain:G,question:"What is the purpose of certificate transparency (CT) logs?",options:["Revoke compromised certificates","A public audit log of all TLS certificates issued, allowing detection of misissued certificates","Replace OCSP for revocation checking","Store private keys for CA recovery"],answer:1,explanation:"CT logs create an auditable, append-only record of all certificates issued by CAs, enabling domain owners to detect unauthorized certs.",optionExplanations:["Certificate revocation is done through CRLs and OCSP; CT logs are for auditing and detection.","CT logs provide public visibility into all certificates issued, so domain owners can spot unexpected or fraudulent certificates.","OCSP handles revocation; CT logs handle issuance auditing.","Private keys must never appear in public logs; CT logs contain only the public certificate data."]},
  {id:337,domain:G,question:"What is a certificate signing request (CSR)?",options:["A request to revoke a certificate","A message sent to a CA containing the public key and identity information, requesting a signed certificate","A digital signature on a certificate","A request to renew an expiring certificate"],answer:1,explanation:"A CSR contains the entity's public key and identity (CN, SAN, organization) and is signed with the corresponding private key.",optionExplanations:["Certificate revocation is requested through the CA's revocation processes; a CSR is for obtaining a new certificate.","A CSR is submitted to the CA with the applicant's public key and information; the CA signs and returns a certificate.","A digital signature on a certificate is the CA's signature; a CSR requests that signature.","Renewal typically involves submitting a new CSR; the process itself is not called a CSR."]},
  {id:338,domain:T,question:"What is a pass-the-certificate attack?",options:["Using a stolen password to log in","Using a stolen digital certificate and key pair to authenticate without knowing the password","A phishing attack using certificate warnings","Forging a root CA certificate"],answer:1,explanation:"Pass-the-certificate reuses stolen certificates and private keys (from certificate stores) to authenticate to services that accept certificate authentication.",optionExplanations:["Using a stolen password is credential theft; pass-the-certificate uses cryptographic material.","Pass-the-certificate extracts certificate/key pairs from certificate stores and uses them to authenticate as the victim.","Certificate warning phishing tricks users into ignoring TLS errors; it is not pass-the-certificate.","Forging CA certificates requires the CA's private key; pass-the-certificate uses legitimate stolen certificates."]},
  {id:339,domain:O,question:"What is the purpose of a deception technology solution?",options:["Prevent all attacks before they happen","Create fake assets and data throughout the environment to detect and slow down attackers who enter the network","Replace traditional detection controls","Train staff in attacker techniques"],answer:1,explanation:"Deception technology (honeypots, honeyfiles, fake credentials) alerts defenders when attackers interact with decoy assets.",optionExplanations:["Deception detects attackers inside the network; it cannot prevent attacks from entering.","Deception technologies create attractive fake targets that alert defenders the moment an attacker interacts with them.","Deception supplements detection; it does not replace firewalls, IDS/IPS, or SIEM.","Red team training teaches attacker techniques; deception technology is a defensive detection mechanism."]},
  {id:340,domain:P,question:"What is the purpose of a security awareness training program metric?",options:["Determine how many security tools are deployed","Measure the effectiveness of training in reducing security risk behaviors among employees","Track attendance for compliance purposes only","Evaluate the technical skills of security staff"],answer:1,explanation:"Meaningful metrics (phishing click rates, reporting rates, policy quiz scores) measure behavioral change, not just compliance.",optionExplanations:["Tool count is a technical inventory metric; training metrics measure human behavior change.","Training metrics quantify whether employees recognize and avoid threats — e.g., reduction in phishing click-through rates.","Attendance tracking satisfies compliance checklists but does not measure whether training changed behavior.","Technical staff skills are measured through separate certification and competency assessments."]},
  {id:341,domain:G,question:"What is the purpose of a security assertion markup language (SAML) assertion?",options:["Encrypt user passwords","An XML document passed from an identity provider to a service provider confirming user authentication","Generate digital signatures for emails","Manage certificate revocation"],answer:1,explanation:"A SAML assertion is an XML statement from the IdP to the SP declaring the user's identity and attributes after authentication.",optionExplanations:["Password encryption is handled by hashing algorithms; SAML assertions are authentication confirmation messages.","SAML assertions carry the IdP's signed confirmation that a user has authenticated, enabling SSO across services.","Email digital signatures use S/MIME or PGP; SAML assertions are web SSO messages.","Certificate revocation uses CRLs and OCSP; SAML is a federation and SSO protocol."]},
  {id:342,domain:G,question:"What is OpenID Connect (OIDC)?",options:["An encryption protocol for API communications","An identity layer built on top of OAuth 2.0 providing authentication and identity information","A key management protocol","A digital certificate standard"],answer:1,explanation:"OIDC adds an identity layer to OAuth 2.0, providing ID tokens (JWT) with user identity claims for authentication.",optionExplanations:["API encryption is handled by TLS; OIDC is an authentication and identity protocol.","OpenID Connect extends OAuth 2.0 with authentication capabilities, issuing ID tokens containing user identity information.","Key management is handled by KMS solutions; OIDC manages identity tokens.","Digital certificates follow X.509 standards; OIDC uses JWT tokens for identity."]},
  {id:343,domain:T,question:"What is a fileless attack that uses PowerShell for malicious purposes called?",options:["A macro virus","A PowerShell-based living-off-the-land attack","A rootkit","A wiper attack"],answer:1,explanation:"Attackers use legitimate PowerShell to download payloads, manipulate systems, and evade detection without dropping files.",optionExplanations:["Macro viruses are embedded in Office documents; PowerShell attacks run in memory.","Using PowerShell for malicious purposes is a prime example of living-off-the-land — no external malware files needed.","Rootkits hide at the kernel level; PowerShell attacks operate at the user/OS level.","Wipers destroy data; PowerShell attacks may destroy, steal, or persist depending on objectives."]},
  {id:344,domain:T,question:"What is the primary security risk of IoT devices?",options:["IoT devices are too expensive","IoT devices often lack security updates, use default credentials, and have minimal security features","IoT devices consume too much bandwidth","IoT devices are difficult to configure"],answer:1,explanation:"IoT devices frequently run outdated firmware, use default credentials, and cannot be patched, creating persistent network vulnerabilities.",optionExplanations:["Cost is a procurement consideration, not a security risk.","IoT devices often run stripped-down OSes without update mechanisms, factory-default passwords, and no security tooling.","Bandwidth consumption is a performance concern; security weaknesses are the primary risk.","Configuration difficulty is a usability issue; the security risk is the lack of security controls."]},
  {id:345,domain:A,question:"What is a VPC (Virtual Private Cloud)?",options:["A virtual private network for users","An isolated, logically defined section of a public cloud provider's infrastructure dedicated to one customer","A type of cloud-based VPN","A private data center hosted at a cloud provider"],answer:1,explanation:"A VPC provides network isolation within a public cloud, allowing customers to define their own IP ranges, subnets, and routing.",optionExplanations:["A VPN creates encrypted tunnels; a VPC is a network isolation construct within a cloud provider.","A VPC is a logically isolated section of a cloud provider's network that a customer fully controls (subnets, routing, security groups).","While a VPC can host VPN endpoints, it is not itself a VPN.","A private data center is on-premises; a VPC is cloud infrastructure logically isolated for a single customer."]},
  {id:346,domain:A,question:"What is the purpose of a cloud security posture management (CSPM) tool?",options:["Encrypt cloud data","Continuously monitor cloud environments for misconfigurations and compliance violations","Provide VPN access to cloud resources","Replace cloud native security controls"],answer:1,explanation:"CSPM tools automatically detect and remediate cloud misconfigurations (public S3 buckets, open security groups) that expose organizations.",optionExplanations:["Data encryption is a cloud security control; CSPM monitors the configuration of those controls.","CSPM identifies cloud infrastructure misconfigurations, policy violations, and compliance deviations automatically.","VPN access is provided by cloud VPN gateways; CSPM monitors security configurations.","CSPM adds visibility and governance on top of native controls; it does not replace them."]},
  {id:347,domain:O,question:"What is the OODA loop and how does it apply to security?",options:["A malware analysis framework","A decision cycle (Observe, Orient, Decide, Act) used by security teams to outpace attackers","An incident classification system","A network monitoring protocol"],answer:1,explanation:"The OODA loop enables faster decision-making cycles than attackers — observing what's happening, orienting to context, deciding, and acting.",optionExplanations:["Malware analysis uses sandbox analysis and reverse engineering; OODA is a decision-making framework.","The OODA (Observe, Orient, Decide, Act) loop helps security teams make rapid, informed decisions to stay ahead of attackers.","Incident classification uses severity levels and categories; OODA is a response decision model.","Network monitoring collects data; OODA is the framework for acting on that data."]},
  {id:348,domain:O,question:"What does IoC (Indicator of Compromise) differ from an IoA (Indicator of Attack)?",options:["They are the same thing","IoCs are evidence of past compromise; IoAs are behavioral patterns indicating an ongoing attack","IoAs are always more accurate than IoCs","IoCs are used for prevention; IoAs are used for detection"],answer:1,explanation:"IoCs (file hashes, IPs) are forensic artifacts after compromise; IoAs (lateral movement patterns) indicate an attack in progress.",optionExplanations:["IoCs and IoAs serve different purposes in the attack timeline.","IoCs are post-compromise artifacts (file hashes, registry keys); IoAs are real-time behavioral indicators of active attack progression.","Both have value; IoAs often provide earlier warning while IoCs confirm compromise.","IoCs support detection and forensics; IoAs enable earlier detection and prevention during an active attack."]},
  {id:349,domain:P,question:"What is the concept of 'privacy engineering'?",options:["Building surveillance systems","Systematically integrating privacy requirements into technical systems throughout the engineering lifecycle","Auditing privacy policies annually","Training developers on GDPR compliance"],answer:1,explanation:"Privacy engineering applies technical methods to identify and mitigate privacy risks throughout system design and development.",optionExplanations:["Surveillance system development is the opposite of privacy engineering.","Privacy engineering integrates privacy impact analysis, data flow mapping, and privacy-preserving design into the development process.","Auditing is a compliance activity; privacy engineering is a proactive design methodology.","GDPR training is awareness; privacy engineering is the technical discipline of building privacy in."]},
  {id:350,domain:G,question:"What is a hybrid encryption scheme?",options:["Using two different symmetric algorithms together","Using asymmetric encryption to protect a symmetric key, then symmetric encryption for bulk data","Encrypting data twice with different keys","Using one key for authentication and another for encryption"],answer:1,explanation:"Hybrid encryption (used in TLS, PGP) uses asymmetric to securely exchange a symmetric key, then symmetric for fast bulk data encryption.",optionExplanations:["Two symmetric algorithms together is double encryption, not hybrid encryption.","Hybrid encryption combines the key management advantages of asymmetric with the speed advantages of symmetric encryption.","Double encryption uses the same type of algorithm twice; hybrid combines asymmetric and symmetric.","Using separate keys for authentication and encryption is dual-use key management; hybrid encryption is about combining algorithm types."]},
  {id:351,domain:T,question:"What is a watering hole attack?",options:["Flooding a server with traffic","Compromising websites frequently visited by a target group to infect their systems","Intercepting communications between two parties","Sending phishing emails to specific individuals"],answer:1,explanation:"Watering hole attacks compromise websites that the target group frequently visits, allowing attackers to infect visitors without direct contact.",optionExplanations:["Flooding a server with traffic is a denial-of-service attack, not a watering hole attack.","Watering hole attacks identify websites targets visit, compromise those sites, and infect visitors through drive-by downloads or exploits.","Intercepting communications is a man-in-the-middle attack; watering hole attacks use compromised websites.","Phishing targets individuals directly; watering hole attacks passively wait for targets to visit compromised sites."]},
  {id:352,domain:G,question:"What is key escrow in cryptography?",options:["Storing keys in a hardware security module","A system where a copy of an encryption key is held by a trusted third party for authorized recovery","Distributing keys across multiple servers","Generating keys from a shared secret"],answer:1,explanation:"Key escrow allows authorized parties (law enforcement, recovery agents) to access encrypted data by retrieving the stored key copy.",optionExplanations:["HSM storage is a key protection mechanism; key escrow is a deliberate backup for recovery or lawful access.","Key escrow intentionally provides a copy to a trusted party, enabling authorized decryption when the original key holder cannot provide access.","Distributing keys across servers is key splitting or threshold cryptography; escrow places a full copy with a trusted party.","Generating keys from shared secrets is Diffie-Hellman; escrow is about storing copies of existing keys."]},
  {id:353,domain:A,question:"What is a jump server (jump box) used for in network security?",options:["Testing network performance","A hardened intermediate host used to access systems in isolated or high-security network segments","Routing traffic between VLANs","Running vulnerability scans on network devices"],answer:1,explanation:"Jump servers provide a controlled access point to sensitive network zones, logging all activity and reducing direct exposure of internal systems.",optionExplanations:["Network performance testing uses dedicated tools like iPerf; a jump box controls administrative access.","A jump server (or bastion host) sits between the administrator and target systems, logging and controlling privileged access to sensitive zones.","VLAN routing is performed by Layer 3 switches or routers; jump boxes control administrative access paths.","Vulnerability scanning tools (Nessus, Qualys) perform scans; jump boxes are access control points."]},
  {id:354,domain:O,question:"What is the primary purpose of security information and event management (SIEM) correlation rules?",options:["Encrypting log data","Identifying patterns across multiple log sources that indicate potential security incidents","Compressing log files for storage","Automatically patching vulnerabilities"],answer:1,explanation:"SIEM correlation rules analyze events from multiple sources to detect attack patterns like brute force, lateral movement, or data exfiltration.",optionExplanations:["Log encryption protects confidentiality; SIEM correlation analyzes log content to detect threats.","Correlation rules match events across sources — failed logins followed by success, then large data transfers — to surface attack sequences.","Log compression reduces storage costs; SIEM correlation extracts meaning from log data.","Patch management addresses vulnerabilities; SIEM detects exploitation of vulnerabilities and other security events."]},
  {id:355,domain:T,question:"What distinguishes a zero-day exploit from a known vulnerability exploit?",options:["Zero-days are less dangerous than known exploits","A zero-day targets a vulnerability unknown to the vendor, while known exploits target published vulnerabilities","Zero-days only affect operating systems","Known exploits are more reliable than zero-days"],answer:1,explanation:"Zero-day exploits target vulnerabilities the vendor doesn't know about, so no patch exists, making them extremely valuable and dangerous.",optionExplanations:["Zero-days are typically more dangerous because no patch exists and detection is harder.","A zero-day exploit targets a previously unknown vulnerability, giving defenders zero days to patch before exploitation occurs.","Zero-days affect any software layer — browsers, applications, firmware, operating systems.","Known exploits may be reliable due to public PoC code, but zero-days have the advantage of no defenses being in place."]},
  {id:356,domain:P,question:"What is the purpose of a data retention policy?",options:["To keep all data forever","To define how long different data types should be kept and when they must be securely deleted","To replicate data to multiple locations","To classify data by sensitivity level"],answer:1,explanation:"Data retention policies balance legal/regulatory requirements (keeping records) with privacy obligations (deleting personal data when no longer needed).",optionExplanations:["Keeping all data forever creates excessive storage costs and privacy liabilities; retention policies set defined timelines.","Retention policies specify periods for different data types (7 years for financial, 3 years for HR) and mandate secure deletion after those periods.","Data replication is a business continuity control; retention policies govern the lifecycle of data.","Data classification determines sensitivity levels; retention policies determine how long to keep data of each classification."]},
  {id:357,domain:A,question:"What is network segmentation and why is it a security control?",options:["Increasing network bandwidth","Dividing a network into isolated zones to limit lateral movement and contain breaches","Encrypting all network traffic","Filtering email attachments at the gateway"],answer:1,explanation:"Network segmentation contains breaches by limiting how far attackers can move — a compromised guest network can't reach production systems.",optionExplanations:["Network bandwidth is a performance concern; segmentation is a security architecture control.","Segmentation creates isolated zones (DMZ, production, HR, guest) with firewall rules between them, limiting blast radius if one zone is compromised.","Traffic encryption (TLS/IPsec) protects data in transit; segmentation controls which systems can communicate with each other.","Email gateway filtering protects against malicious content; segmentation controls network-level communications."]},
  {id:358,domain:O,question:"What is the goal of a tabletop exercise in incident response?",options:["Testing technical response tools","A discussion-based simulation where team members work through a scenario to identify gaps in plans and procedures","Measuring network latency under attack conditions","Validating backup restoration procedures"],answer:1,explanation:"Tabletop exercises identify communication gaps, unclear responsibilities, and missing procedures without executing actual response actions.",optionExplanations:["Technical tool testing occurs in functional exercises and drills; tabletop is discussion-based.","Tabletop exercises walk through a hypothetical scenario verbally, revealing gaps in roles, escalation paths, decision-making, and communication.","Network performance testing is separate from incident response planning; tabletops focus on process and decision gaps.","Backup validation is a technical recovery test; tabletop exercises focus on people and process, not technical systems."]},
  {id:359,domain:G,question:"What is the difference between symmetric and asymmetric encryption in terms of key management?",options:["Symmetric uses two keys; asymmetric uses one","Symmetric uses a single shared secret key; asymmetric uses a public/private key pair","They use the same key management approach","Asymmetric requires hardware security modules"],answer:1,explanation:"Symmetric key distribution is the challenge (how to share the secret securely); asymmetric solves this with freely shareable public keys.",optionExplanations:["Symmetric uses one shared key; asymmetric uses mathematically linked key pairs.","Symmetric encryption uses one key for both encryption and decryption, requiring secure key exchange; asymmetric uses key pairs where the public key can be freely shared.","Asymmetric and symmetric have fundamentally different key management approaches — the public/private pair eliminates the key distribution problem.","While HSMs can store asymmetric keys, they are not required; asymmetric keys can be stored in software keystores."]},
  {id:360,domain:T,question:"What is credential stuffing?",options:["Creating fake credentials for testing","Using stolen username/password pairs from one breach to attempt login on other services","Brute-forcing password hashes","Embedding credentials in malware"],answer:1,explanation:"Credential stuffing exploits password reuse — attackers take breach dumps and try those credentials against banks, email, and other high-value sites.",optionExplanations:["Creating test credentials is a development practice; credential stuffing uses stolen real credentials.","Credential stuffing uses credential databases from previous breaches to automate login attempts across many services, exploiting password reuse.","Brute forcing hashes is offline cracking; credential stuffing attempts live logins with complete username/password pairs.","Embedding credentials in malware is hardcoded credentials; credential stuffing is an automated attack using breach data."]},
  {id:361,domain:A,question:"What is a software-defined perimeter (SDP)?",options:["A virtual firewall","A security framework that dynamically creates one-to-one network connections between users and resources they are authorized to access","A DMZ implemented in software","A cloud-based IDS system"],answer:1,explanation:"SDP hides network resources until after authentication and authorization, making infrastructure invisible to unauthorized users (implements zero trust).",optionExplanations:["Virtual firewalls inspect traffic; SDP makes resources invisible until authenticated — a fundamentally different approach.","SDP (also called black cloud) authenticates users first, then dynamically provisions encrypted connections only to authorized resources, never exposing the network.","A software DMZ is still a traditional network zone; SDP eliminates the perimeter concept entirely.","Cloud IDS monitors for threats; SDP controls access by making resources invisible to unauthenticated users."]},
  {id:362,domain:O,question:"What is the purpose of a business impact analysis (BIA)?",options:["Analyzing competitor business strategies","Identifying critical business functions and quantifying the impact of their disruption on the organization","Reviewing IT system performance metrics","Assessing employee productivity levels"],answer:1,explanation:"The BIA identifies critical functions, recovery time objectives (RTO), recovery point objectives (RPO), and financial impact of downtime.",optionExplanations:["Competitor analysis is a business intelligence activity; BIA focuses on internal operations and their recovery requirements.","A BIA identifies which processes are most critical, the maximum tolerable downtime, data loss tolerance, and financial/reputational impact of disruptions.","IT performance metrics are operational monitoring; BIA establishes business recovery requirements that drive IT continuity planning.","Employee productivity is an HR concern; BIA focuses on process criticality and disruption impact quantification."]},
  {id:363,domain:T,question:"What is a living off the land (LotL) attack technique?",options:["Planting physical devices in target facilities","Using legitimate built-in system tools (PowerShell, WMI, certutil) to conduct malicious activities without deploying custom malware","Attacking IoT devices in agricultural settings","Using social engineering to gain physical access"],answer:1,explanation:"LotL attacks abuse trusted tools already present on systems, making detection difficult since the tools are legitimate and expected to run.",optionExplanations:["Physical device planting is a hardware-based attack; LotL uses existing software tools.","LotL attackers use PowerShell, WMI, certutil, and other built-in Windows/Linux tools to evade detection because these tools are expected to be running.","LotL is a technique applicable to any environment; it's not specific to agricultural or IoT contexts.","Physical access via social engineering is a different attack vector; LotL refers specifically to using native system tools for malicious purposes."]},
  {id:364,domain:G,question:"What is the role of a certificate revocation list (CRL)?",options:["A list of trusted root certificates","A published list of certificates that have been revoked before their expiration date","A list of certificates pending renewal","A registry of all issued certificates"],answer:1,explanation:"CRLs allow relying parties to check if a certificate has been revoked due to key compromise, CA compromise, or policy violation.",optionExplanations:["Trusted root certificates are stored in a trust store; CRLs list revoked certificates.","A CRL lists certificate serial numbers that have been invalidated, allowing clients to verify a certificate hasn't been revoked before trusting it.","Renewal lists are managed internally by CAs; CRLs publish revocation status to the public.","Certificate registries track issuance; CRLs specifically list certificates that are no longer trustworthy despite not yet being expired."]},
  {id:365,domain:P,question:"What is a privacy impact assessment (PIA)?",options:["An assessment of data center physical security","A systematic process for evaluating the privacy risks of collecting or processing personal information","An audit of employee privacy training completion","A review of network security controls"],answer:1,explanation:"PIAs identify how personal data will be collected, used, stored, and shared, and assess risks to individuals' privacy rights.",optionExplanations:["Physical security assessments evaluate facility controls; PIAs analyze data privacy risks.","A PIA examines the data lifecycle — what's collected, why, how long kept, who can access it — and identifies risks and mitigations for privacy rights.","Training audits are compliance checks; PIAs are risk assessments of specific data processing activities.","Network security reviews are technical assessments; PIAs focus on the legal and ethical dimensions of personal data handling."]},
  {id:366,domain:A,question:"What is microsegmentation in cloud and virtualized environments?",options:["Dividing a physical server into multiple VMs","Applying fine-grained security policies at the individual workload level, controlling east-west traffic between workloads","Segmenting network traffic by size","Creating separate cloud regions for each application"],answer:1,explanation:"Microsegmentation applies policies between individual VMs or containers, preventing lateral movement even within the same network segment.",optionExplanations:["Creating VMs from a physical server is virtualization; microsegmentation is a security policy applied to those VMs.","Microsegmentation enforces security policies at the workload level, controlling traffic between individual services and preventing attackers from moving laterally between systems.","Traffic segmentation by packet size is a QoS concept; microsegmentation is about security policy enforcement between workloads.","Multiple cloud regions provide redundancy; microsegmentation provides granular security policy within environments."]},
  {id:367,domain:O,question:"What is threat hunting?",options:["Running automated vulnerability scans","Proactively searching through networks and systems for signs of compromise that evaded automated detection","Setting up honeypots to attract attackers","Responding to alerts generated by security tools"],answer:1,explanation:"Threat hunters assume compromise has occurred and use hypotheses, data analysis, and security expertise to find hidden attackers.",optionExplanations:["Vulnerability scanning finds weaknesses; threat hunting looks for active adversaries that have already penetrated defenses.","Threat hunting is a proactive, analyst-driven search for adversaries using TTPs, hypotheses, and anomaly analysis to find what automated tools missed.","Honeypots are deception technology; threat hunting actively searches production systems for signs of compromise.","Responding to alerts is reactive security operations; threat hunting is proactive and assumes automated detection has already failed."]},
  {id:368,domain:T,question:"What is a command and control (C2) server in the context of malware?",options:["A server that manages user authentication","Infrastructure controlled by attackers that sends commands to and receives data from compromised machines","A legitimate server for software updates","A server that detects and removes malware"],answer:1,explanation:"C2 infrastructure allows attackers to control botnets and malware remotely, issuing instructions and exfiltrating data from compromised hosts.",optionExplanations:["Authentication servers manage identity; C2 servers control compromised endpoints.","C2 (or C&C) servers are attacker-controlled infrastructure that maintains communication with malware on victim systems, enabling remote control and data exfiltration.","Software update servers are legitimate infrastructure; C2 servers are malicious infrastructure mimicking legitimate communications.","Security tools detect and remove malware; C2 servers enable attackers to operate and direct that malware."]},
  {id:369,domain:G,question:"What is forward secrecy (perfect forward secrecy)?",options:["Encrypting future communications in advance","A property ensuring that session keys are not compromised even if the server's private key is later compromised","Forwarding encrypted packets to multiple destinations","Generating backup keys before certificate expiration"],answer:1,explanation:"PFS uses ephemeral key exchange (ECDHE/DHE) so each session has a unique key — past traffic stays secure even if the private key is stolen later.",optionExplanations:["Encrypting future communications in advance is not a real security concept; PFS protects past sessions from future key compromise.","Perfect forward secrecy generates ephemeral session keys that are discarded after use, so compromising the long-term private key cannot decrypt recorded past sessions.","Forwarding encrypted packets is a routing concept; PFS is a key exchange property ensuring past session keys remain secure.","Backup key generation is key management; PFS is a property of ephemeral key exchange protocols."]},
  {id:370,domain:O,question:"What is the difference between RTO and RPO in disaster recovery?",options:["They are identical metrics","RTO is the maximum acceptable downtime before recovery; RPO is the maximum acceptable data loss measured in time","RTO applies to databases; RPO applies to applications","RPO measures recovery speed; RTO measures data backup frequency"],answer:1,explanation:"RTO (Recovery Time Objective) defines how quickly systems must be restored; RPO (Recovery Point Objective) defines how much data loss is acceptable.",optionExplanations:["RTO and RPO are distinct metrics addressing different aspects of recovery requirements.","RTO asks 'how long can we be down?' (e.g., 4 hours); RPO asks 'how much data can we lose?' (e.g., last 1 hour of transactions).","Both metrics apply to any critical system or application, not specific technology categories.","RPO determines backup frequency needed to meet data loss tolerance; RTO determines infrastructure needed to meet recovery time goals."]},
  {id:371,domain:T,question:"What is a rootkit?",options:["A collection of administrator scripts","Malware that gains and hides deep OS-level access, concealing its presence and other malware from the system","A legitimate remote access tool","A tool for managing system root accounts"],answer:1,explanation:"Rootkits modify the OS kernel or bootloader to hide processes, files, and network connections, making detection and removal extremely difficult.",optionExplanations:["Administrator scripts are legitimate management tools; rootkits are malicious and designed for concealment.","Rootkits subvert OS functions to hide malicious activity — they intercept system calls to filter out their own processes, files, and registry keys from security tools.","Remote access tools (RATs) provide remote control; rootkits specifically provide stealth by hiding the attacker's presence.","Root account management tools control privileges; rootkits exploit root/kernel access to persist and hide."]},
  {id:372,domain:A,question:"What is a web application firewall (WAF) designed to protect against?",options:["Network-level DDoS attacks","Application-layer attacks targeting web applications, such as SQL injection, XSS, and CSRF","Malware on endpoint devices","Unauthorized physical access to web servers"],answer:1,explanation:"WAFs inspect HTTP/HTTPS traffic and block attacks targeting application logic — things traditional network firewalls cannot detect.",optionExplanations:["Network DDoS is mitigated by anti-DDoS services and network firewalls; WAFs protect web application logic.","WAFs analyze HTTP requests and responses, detecting and blocking application-layer attacks like SQL injection, XSS, path traversal, and bot attacks.","Endpoint malware is addressed by EDR/antivirus; WAFs protect web application layers from remote attack.","Physical access controls are separate; WAFs protect against remote application-layer attacks through web protocols."]},
  {id:373,domain:P,question:"What is the right to erasure (right to be forgotten) under GDPR?",options:["The right to delete others' data","An individual's right to request deletion of their personal data when it is no longer necessary or consent is withdrawn","The right to prevent automated decision-making","A right to access all data held about an individual"],answer:1,explanation:"Article 17 GDPR allows individuals to request deletion of their personal data under specific circumstances, including withdrawal of consent.",optionExplanations:["The right to erasure applies to one's own personal data; you cannot request deletion of data about others.","GDPR Article 17 gives individuals the right to request organizations delete their personal data when processing is no longer justified, consent is withdrawn, or data was processed unlawfully.","The right to object to automated decision-making is GDPR Article 22; erasure is Article 17.","The right of access (Article 15) allows seeing held data; erasure (Article 17) allows requesting its deletion."]},
  {id:374,domain:G,question:"What is salting in the context of password storage?",options:["Encrypting passwords with a master key","Adding a unique random value to each password before hashing to prevent rainbow table attacks","Compressing password databases","Adding complexity requirements to passwords"],answer:1,explanation:"Salts ensure identical passwords produce different hashes, defeating precomputed rainbow table attacks and making per-password cracking necessary.",optionExplanations:["Encrypting passwords is different from hashing; salting is a technique used with hashing, not encryption.","A salt is a unique random string prepended or appended to each password before hashing, ensuring two identical passwords produce completely different stored hashes.","Password database compression is a storage optimization; salting is a security technique protecting hashes from precomputed attacks.","Password complexity requirements are policy controls; salting is a technical hash protection mechanism applied during storage."]},
  {id:375,domain:O,question:"What is the purpose of security orchestration, automation, and response (SOAR)?",options:["Replacing human security analysts entirely","Automating repetitive security tasks and coordinating responses across security tools to improve efficiency and speed","Providing a single security dashboard","Performing automated penetration testing"],answer:1,explanation:"SOAR platforms run playbooks to automatically triage alerts, enrich data, contain threats, and coordinate multi-tool response actions.",optionExplanations:["SOAR augments security analysts by handling routine tasks; human judgment remains essential for complex decisions.","SOAR platforms automate repetitive tasks (IP lookups, ticket creation, containment actions) and orchestrate workflows across SIEM, EDR, firewall, and ticketing systems.","A single dashboard is a feature of SIEM and security operations centers; SOAR is about automated action and workflow.","Automated penetration testing tools are separate security products; SOAR focuses on detecting and responding to real incidents."]},
  {id:376,domain:T,question:"What is pretexting in social engineering?",options:["Sending mass phishing emails","Creating a fabricated scenario or false identity to manipulate a target into providing information or access","Threatening targets with legal action to extract information","Installing fake websites to capture credentials"],answer:1,explanation:"Pretexting involves creating a believable false context (impersonating IT support, auditors, vendors) to make targets comply with requests.",optionExplanations:["Mass phishing emails are phishing attacks without sophisticated pretexts; pretexting involves a specific narrative.","Pretexting builds a detailed false scenario to establish trust — pretending to be a coworker needing urgent help, an auditor requiring access, or a vendor verifying an order.","Threatening legal action is intimidation/vishing; pretexting uses persuasion through false identity rather than threats.","Fake websites for credential capture are pharming or phishing; pretexting is a social manipulation technique focused on human interaction."]},
  {id:377,domain:A,question:"What is the purpose of a hardware security module (HSM)?",options:["Providing physical server rack security","A tamper-resistant hardware device that securely stores and manages cryptographic keys and performs cryptographic operations","Monitoring hardware component temperatures","Encrypting hard drives"],answer:1,explanation:"HSMs protect private keys by ensuring they never leave the hardware boundary, with tamper-evident mechanisms that destroy keys if tampering is detected.",optionExplanations:["Physical rack security is a data center concern; HSMs protect cryptographic material.","HSMs are purpose-built hardware devices with physical tamper protection that generate, store, and use keys — private keys never leave the HSM in plaintext.","Temperature monitoring is infrastructure management; HSMs perform cryptographic operations with keys stored in protected hardware.","Drive encryption software can use keys; HSMs are where those keys are generated and securely stored."]},
  {id:378,domain:O,question:"What is the mean time to detect (MTTD) security metric?",options:["Average time to fix vulnerabilities","The average time from when a threat actor gains access until the organization detects the compromise","Average time to complete security training","The typical duration of a DDoS attack"],answer:1,explanation:"MTTD measures detection capability — lower is better. The industry average has historically been months, giving attackers time to cause significant damage.",optionExplanations:["Mean time to fix/remediate vulnerabilities is MTTR (Mean Time to Repair/Remediate); MTTD is specifically about detection.","MTTD measures the gap between initial compromise and discovery, representing the attacker's dwell time and opportunity to cause damage.","Security training completion time is a compliance metric; MTTD is an operational security effectiveness measurement.","DDoS attack duration varies; MTTD measures the organization's ability to detect any type of compromise."]},
];
